SELECT 
  FROM sla_instance
 WHERE tenant_id=#{tenantId} AND project_id=#{projectId}
AND work_order_id=#{workOrderId}
AND status=#{status}

    AND (deadline_at, sla_instance_id) > (#{cursorDeadlineAt}, #{cursorId})

 ORDER BY deadline_at, sla_instance_id
 LIMIT #{fetchSize}

SELECT 
  FROM sla_instance
 WHERE tenant_id=#{tenantId} AND sla_instance_id=#{slaInstanceId}
